import React, { useRef, useState } from "react";
import Forecast from "./Forecast";
import BottomBar from "./BottomBar";
import WeatherOverlay from "./WeatherOverlay";

const WeatherApp = () => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [activeTab, setActiveTab] = useState("now");
  const [selectedCity, setSelectedCity] = useState("Atlanta, US");
  const forecastRef = useRef(null);
  const topRef = useRef(null);

  const weatherCards = [
    { id: 1, title: "Temperature", value: "28°C", icon: "🌤️" },
    { id: 2, title: "Humidity", value: "65%", icon: "💧" },
    { id: 3, title: "Wind", value: "14 km/h", icon: "💨" },
  ];

  const favoriteCities = [
    "Atlanta, US",
    "New York, US",
    "London, UK",
    "Dubai, AE",
  ];

  const handleScroll = (e) => {
    const cardWidth = e.target.offsetWidth;
    const newIndex = Math.round(e.target.scrollLeft / cardWidth);
    setActiveIndex(newIndex);
  };

  const handleSelectTab = (key) => {
    setActiveTab(key);
    if (key === "forecast" && forecastRef.current) {
      forecastRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
    }
    if (key === "now" && topRef.current) {
      topRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  };

  return (
    <div ref={topRef} className="relative min-h-screen flex flex-col items-center pb-24">
      {/* Dynamic Weather Overlay */}
      <WeatherOverlay city={selectedCity} />

      {/* Top Search Bar */}
      <div className="sticky top-0 z-50 w-full px-4 py-2 bg-black/60 backdrop-blur-md shadow-md flex items-center justify-between">
        <input
          type="text"
          placeholder="Search city..."
          className="flex-1 px-3 py-1 rounded-lg bg-black/50 text-white placeholder-gray-400 outline-none mr-3"
        />
        <button className="text-purple-400 hover:text-purple-300">🔍</button>
      </div>

      {/* Favorite Cities */}
      <div className="w-full px-4 mt-3 flex space-x-3 overflow-x-auto scrollbar-hide">
        {favoriteCities.map((city) => (
          <button
            key={city}
            onClick={() => setSelectedCity(city)}
            className={`px-4 py-2 rounded-full text-sm whitespace-nowrap transition ${
              selectedCity === city
                ? "bg-purple-500 text-white"
                : "bg-black/50 text-white hover:bg-purple-500/60"
            }`}
          >
            {city}
          </button>
        ))}
      </div>

      {/* Current City Name */}
      <div className="w-full px-4 mt-4">
        <h1 className="text-2xl font-semibold text-white drop-shadow-md">
          {selectedCity}
        </h1>
      </div>

      {/* Main Weather Cards */}
      {/* Mobile: long rectangles */}
      <div
        className="w-full sm:hidden overflow-x-auto snap-x snap-mandatory flex space-x-4 px-4 pb-3 pt-4"
        onScroll={handleScroll}
      >
        {weatherCards.map((card) => (
          <div
            key={card.id}
            className="snap-center w-full flex-shrink-0 bg-black/60 backdrop-blur-md text-white rounded-2xl p-4 flex justify-between items-center shadow-lg"
          >
            <div>
              <h2 className="text-base">{card.title}</h2>
              <p className="text-2xl font-bold">{card.value}</p>
            </div>
            <div className="text-4xl">{card.icon}</div>
          </div>
        ))}
      </div>

      {/* Pagination Dots for Mobile */}
      <div className="sm:hidden flex justify-center space-x-2 mb-4">
        {weatherCards.map((_, idx) => (
          <span
            key={idx}
            className={`h-2 w-2 rounded-full ${
              activeIndex === idx ? "bg-purple-500" : "bg-gray-500/60"
            }`}
          />
        ))}
      </div>

      {/* Desktop: squares */}
      <div className="hidden sm:grid sm:grid-cols-3 gap-4 px-4 w-full max-w-5xl mt-4">
        {weatherCards.map((card) => (
          <div
            key={card.id}
            className="bg-black/60 backdrop-blur-md text-white rounded-xl p-4 flex flex-col justify-center items-center shadow-lg aspect-square hover:ring-1 hover:ring-purple-500/40 transition"
          >
            <div className="text-4xl mb-2">{card.icon}</div>
            <h2 className="text-lg">{card.title}</h2>
            <p className="text-2xl font-bold">{card.value}</p>
          </div>
        ))}
      </div>

      {/* Forecast Section */}
      <div ref={forecastRef} className="mt-12 w-full px-4 max-w-5xl">
        <Forecast city={selectedCity} layout="responsive" />
      </div>

      {/* Glass Bottom Bar */}
      <BottomBar active={activeTab} onSelect={handleSelectTab} />
    </div>
  );
};

export default WeatherApp;
